def is_spam_rules(email):
    bad = ["win a prize", "click here now", "free money"]
    return any(phrase in email.lower() for phrase in bad)

print(is_spam_rules("Win a prize now!"))
print(is_spam_rules("W1n a pr1ze now!"))

